form:Form.form:Scripts:
		function LoadForm()
{
	if(Ctrl('oi_estudio'))
		ChangeEstudio();
}

function ChangeEstudio()
{	
	if(Ctrl('oi_estudio').GetXValue() != "") 
	{
		if(Ctrl('d_otro_est_educ'))
			Ctrl('d_otro_est_educ').SetXValue("");
		CtrlEnabled('d_otro_est_educ', false);		
	}
	else
	{		
		CtrlEnabled('d_otro_est_educ', true);
	}	
}
